import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxLength = 10; // Maximum length allowed for buffer
        char[] buffer = new char[maxLength];

        // Copy user input into the buffer with bounds checking
        for (int i = 0; i < userInput.length() && i < maxLength; i++) {
            buffer[i] = userInput.charAt(i);
        }

        if (userInput.length() > maxLength) {
            System.out.println("Input exceeds buffer size. Only first " + maxLength + " characters are stored.");
        } else {
            System.out.println("Input successfully stored in buffer.");
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
